import{_ as a,o as t,c as s,ag as i}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"FAQ","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),l={name:"faq.md"};function o(r,e,d,n,h,c){return t(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h1><h2 id="what-shells-are-supported" tabindex="-1">What shells are supported? <a class="header-anchor" href="#what-shells-are-supported" aria-label="Permalink to &quot;What shells are supported?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shell</th><th>Status</th></tr></thead><tbody><tr><td>Fish</td><td>Fully supported and tested</td></tr><tr><td>PowerShell</td><td>Supported and tested (5.1 + 7)</td></tr><tr><td>Zsh</td><td>Supported, not yet tested</td></tr><tr><td>Bash</td><td>Supported (3.2+)</td></tr><tr><td>Nushell</td><td>Not yet implemented</td></tr></tbody></table><h2 id="how-is-this-different-from-shell-aliases-in-my-dotfiles" tabindex="-1">How is this different from shell aliases in my dotfiles? <a class="header-anchor" href="#how-is-this-different-from-shell-aliases-in-my-dotfiles" aria-label="Permalink to &quot;How is this different from shell aliases in my dotfiles?&quot;">​</a></h2><p>Traditional aliases are static — defined once in your <code>.bashrc</code> or <code>.zshrc</code>. amoxide adds:</p><ul><li><strong>Profiles</strong> — named groups you can activate/deactivate without editing files</li><li><strong>Project aliases</strong> — auto-loaded per directory, like direnv for aliases</li><li><strong>Parameterized aliases</strong> — template syntax for composable commands</li><li><strong>Multiple active profiles</strong> — layer aliases with clear precedence</li></ul><h2 id="where-are-my-aliases-stored" tabindex="-1">Where are my aliases stored? <a class="header-anchor" href="#where-are-my-aliases-stored" aria-label="Permalink to &quot;Where are my aliases stored?&quot;">​</a></h2><ul><li><strong>Global and profile aliases:</strong> <code>~/.config/amoxide/config.toml</code></li><li><strong>Project aliases:</strong> <code>.aliases</code> file in the project directory</li></ul><h2 id="can-i-use-amoxide-alongside-my-existing-shell-aliases" tabindex="-1">Can I use amoxide alongside my existing shell aliases? <a class="header-anchor" href="#can-i-use-amoxide-alongside-my-existing-shell-aliases" aria-label="Permalink to &quot;Can I use amoxide alongside my existing shell aliases?&quot;">​</a></h2><p>Yes. amoxide aliases coexist with your shell&#39;s native aliases. If there&#39;s a name conflict, amoxide&#39;s alias takes precedence while it&#39;s active.</p><h2 id="what-is-am-tui" tabindex="-1">What is <code>am-tui</code>? <a class="header-anchor" href="#what-is-am-tui" aria-label="Permalink to &quot;What is `am-tui`?&quot;">​</a></h2><p>A separate binary (<code>amoxide-tui</code>) that provides an interactive terminal UI for managing aliases visually. Once installed, it integrates directly into <code>am</code>:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">am</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tui</span></span></code></pre></div><p>The <code>am tui</code> command launches the TUI — no need to remember a separate binary name. Quick install:</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sassman/tap/amoxide-tui</span></span></code></pre></div><p>See <a href="/guide/installation.html#installing-am-tui">all installation options</a> for Shell Script, PowerShell, and Cargo.</p><p>:::</p>',17)])])}const u=a(l,[["render",o]]);export{m as __pageData,u as default};
